import django
from django.conf import settings
settings.configure(TEMPLATES=[{'BACKEND': 'django.template.backends.django.DjangoTemplates'}])
django.setup()

from django import template

register = template.Library()

@register.simple_tag
def hello(*, greeting='hello'):
    return f'{greeting} world'

@register.simple_tag
def hi(*, greeting):
    return f'{greeting} world'

# Test 1: keyword-only arg with default
print('Test 1: keyword-only arg with default')
try:
    t = template.Template('{% load test_tags %}{% hello greeting=\"hi\" %}')
    print('ERROR: Should have raised TemplateSyntaxError')
except Exception as e:
    print(f'Got: {type(e).__name__}: {e}')

# Test 2: duplicate keyword-only arg without default
print()
print('Test 2: duplicate keyword-only arg without default')
try:
    t = template.Template('{% load test_tags %}{% hi greeting=\"hi\" greeting=\"hello\" %}')
    print('ERROR: Should have raised TemplateSyntaxError')
except Exception as e:
    print(f'Got: {type(e).__name__}: {e}')
"
"}

